import{_ as s,c as t,a,o}from"./app-CwFsTuGQ.js";const n={};function d(r,e){return o(),t("div",null,e[0]||(e[0]=[a(`<h1 id="metrics" tabindex="-1"><a class="header-anchor" href="#metrics"><span>Metrics</span></a></h1><p>FluxaORM provides Prometheus metrics for MySQL queries and Redis commands that you can use to monitor database and Redis usage.</p><h2 id="enabling-metrics" tabindex="-1"><a class="header-anchor" href="#enabling-metrics"><span>Enabling Metrics</span></a></h2><p>By default, metrics are disabled. To enable metrics, provide a <code>promauto.Factory</code> from the Prometheus client library to the registry:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token keyword">import</span> <span class="token punctuation">(</span></span>
<span class="line">    <span class="token string">&quot;github.com/prometheus/client_golang/prometheus&quot;</span></span>
<span class="line">    <span class="token string">&quot;github.com/prometheus/client_golang/prometheus/promauto&quot;</span></span>
<span class="line"></span>
<span class="line">    <span class="token string">&quot;github.com/latolukasz/fluxaorm/v2&quot;</span></span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">func</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    registry <span class="token operator">:=</span> fluxaorm<span class="token punctuation">.</span><span class="token function">NewRegistry</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">    registerer <span class="token operator">:=</span> prometheus<span class="token punctuation">.</span><span class="token function">WrapRegistererWith</span><span class="token punctuation">(</span><span class="token keyword">map</span><span class="token punctuation">[</span><span class="token builtin">string</span><span class="token punctuation">]</span><span class="token builtin">string</span><span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">,</span> prometheus<span class="token punctuation">.</span>DefaultRegisterer<span class="token punctuation">)</span></span>
<span class="line">    factory <span class="token operator">:=</span> promauto<span class="token punctuation">.</span><span class="token function">With</span><span class="token punctuation">(</span>registerer<span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">    registry<span class="token punctuation">.</span><span class="token function">EnableMetrics</span><span class="token punctuation">(</span>factory<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="mysql-metrics" tabindex="-1"><a class="header-anchor" href="#mysql-metrics"><span>MySQL Metrics</span></a></h2><h3 id="fluxaorm-db-queries-seconds-histogram" tabindex="-1"><a class="header-anchor" href="#fluxaorm-db-queries-seconds-histogram"><span><code>fluxaorm_db_queries_seconds</code> (Histogram)</span></a></h3><p>Tracks the duration of all DB queries.</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line"># HELP Total number of DB queries executed</span>
<span class="line"># TYPE fluxaorm_db_queries_seconds histogram</span>
<span class="line">fluxaorm_db_queries_seconds{le=&quot;0.005&quot;,operation=&quot;exec&quot;,pool=&quot;default&quot;,source=&quot;default&quot;} 100</span>
<span class="line">...</span>
<span class="line">fluxaorm_db_queries_seconds_sum{operation=&quot;exec&quot;,pool=&quot;default&quot;,source=&quot;default&quot;} 12.345</span>
<span class="line">fluxaorm_db_queries_seconds_count{operation=&quot;exec&quot;,pool=&quot;default&quot;,source=&quot;default&quot;} 500</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Labels:</strong></p><table><thead><tr><th>Label</th><th>Values</th><th>Description</th></tr></thead><tbody><tr><td><code>operation</code></td><td><code>transaction</code>, <code>select</code>, <code>exec</code></td><td>Type of SQL operation</td></tr><tr><td><code>pool</code></td><td>pool code string</td><td>The MySQL pool code (e.g. <code>&quot;default&quot;</code>)</td></tr><tr><td><code>source</code></td><td>source string</td><td>Metrics source tag (default: <code>&quot;default&quot;</code>)</td></tr></tbody></table><p>The <code>operation</code> label values:</p><ul><li><code>transaction</code> -- BEGIN, COMMIT, ROLLBACK</li><li><code>select</code> -- SELECT queries</li><li><code>exec</code> -- INSERT, UPDATE, DELETE queries</li></ul><h3 id="fluxaorm-db-queries-errors-counter" tabindex="-1"><a class="header-anchor" href="#fluxaorm-db-queries-errors-counter"><span><code>fluxaorm_db_queries_errors</code> (Counter)</span></a></h3><p>Counts the total number of DB query errors.</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line"># HELP Total number of DB queries errors</span>
<span class="line"># TYPE fluxaorm_db_queries_errors counter</span>
<span class="line">fluxaorm_db_queries_errors{pool=&quot;default&quot;,source=&quot;default&quot;} 123</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Labels:</strong></p><table><thead><tr><th>Label</th><th>Values</th><th>Description</th></tr></thead><tbody><tr><td><code>pool</code></td><td>pool code string</td><td>The MySQL pool code</td></tr><tr><td><code>source</code></td><td>source string</td><td>Metrics source tag</td></tr></tbody></table><h2 id="redis-metrics" tabindex="-1"><a class="header-anchor" href="#redis-metrics"><span>Redis Metrics</span></a></h2><h3 id="fluxaorm-redis-queries-seconds-histogram" tabindex="-1"><a class="header-anchor" href="#fluxaorm-redis-queries-seconds-histogram"><span><code>fluxaorm_redis_queries_seconds</code> (Histogram)</span></a></h3><p>Tracks the duration of all Redis queries.</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line"># HELP Total number of Redis queries executed</span>
<span class="line"># TYPE fluxaorm_redis_queries_seconds histogram</span>
<span class="line">fluxaorm_redis_queries_seconds{le=&quot;0.005&quot;,operation=&quot;key&quot;,pool=&quot;default&quot;,set=&quot;1&quot;,miss=&quot;0&quot;,pipeline=&quot;0&quot;,source=&quot;default&quot;} 100</span>
<span class="line">...</span>
<span class="line">fluxaorm_redis_queries_seconds_sum{operation=&quot;key&quot;,pool=&quot;default&quot;,set=&quot;1&quot;,miss=&quot;0&quot;,pipeline=&quot;0&quot;,source=&quot;default&quot;} 12.345</span>
<span class="line">fluxaorm_redis_queries_seconds_count{operation=&quot;key&quot;,pool=&quot;default&quot;,set=&quot;1&quot;,miss=&quot;0&quot;,pipeline=&quot;0&quot;,source=&quot;default&quot;} 500</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Labels:</strong></p><table><thead><tr><th>Label</th><th>Values</th><th>Description</th></tr></thead><tbody><tr><td><code>operation</code></td><td><code>key</code>, <code>list</code>, <code>hash</code>, <code>set</code>, <code>stream</code>, <code>search</code>, <code>lock</code>, <code>other</code></td><td>Category of Redis command</td></tr><tr><td><code>pool</code></td><td>pool code string</td><td>The Redis pool code (e.g. <code>&quot;default&quot;</code>)</td></tr><tr><td><code>set</code></td><td><code>0</code>, <code>1</code></td><td><code>1</code> if the operation writes data, <code>0</code> if it reads</td></tr><tr><td><code>miss</code></td><td><code>0</code>, <code>1</code></td><td><code>1</code> if a read operation missed (key not found), <code>0</code> otherwise</td></tr><tr><td><code>pipeline</code></td><td><code>0</code>, <code>1</code></td><td><code>1</code> if executed inside a pipeline, <code>0</code> otherwise</td></tr><tr><td><code>source</code></td><td>source string</td><td>Metrics source tag (default: <code>&quot;default&quot;</code>)</td></tr></tbody></table><p>The <code>operation</code> label values:</p><ul><li><code>key</code> -- GET, SET, MSET, MGET, DEL, EXISTS, SETNX, INCR, INCRBY, EXPIRE, ...</li><li><code>list</code> -- LPUSH, RPUSH, LPOP, RPOP, LLEN, LRANGE, LINDEX, LSET, LMOVE, BLMOVE, LREM, LTRIM, ...</li><li><code>hash</code> -- HSET, HDEL, HGET, HMGET, HGETALL, HLEN, HINCRBY, HSETNX, ...</li><li><code>set</code> -- ZADD, ZCARD, ZCOUNT, ZSCORE, ZREVRANGE, ZRANGEWITHSCORES, SADD, SMEMBERS, SISMEMBER, SCARD, SPOP, ...</li><li><code>stream</code> -- XADD, XTRIM, XRANGE, XREVRANGE, XLEN, XREAD, XREADGROUP, XACK, XDEL, XINFO, XPENDING, XCLAIM, XAUTOCLAIM, ...</li><li><code>search</code> -- FT.LIST, FT.SEARCH, FT.CREATE, FT.INFO, FT.DROPINDEX, ...</li><li><code>lock</code> -- LOCK OBTAIN, LOCK RELEASE, LOCK TTL, LOCK REFRESH</li><li><code>other</code> -- INFO, EVAL, EVALSHA, SCRIPTLOAD, SCRIPTEXISTS, FLUSHALL, FLUSHDB, SCAN, ...</li></ul><h3 id="fluxaorm-redis-queries-block-counter" tabindex="-1"><a class="header-anchor" href="#fluxaorm-redis-queries-block-counter"><span><code>fluxaorm_redis_queries_block</code> (Counter)</span></a></h3><p>Counts the total number of blocking Redis queries (e.g. blocking <code>XREADGROUP</code> calls with a positive block time).</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line"># HELP Total number of Redis blocking queries executed</span>
<span class="line"># TYPE fluxaorm_redis_queries_block counter</span>
<span class="line">fluxaorm_redis_queries_block{operation=&quot;stream&quot;,pool=&quot;default&quot;,source=&quot;default&quot;} 42</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Labels:</strong></p><table><thead><tr><th>Label</th><th>Values</th><th>Description</th></tr></thead><tbody><tr><td><code>operation</code></td><td>operation string</td><td>The operation type (e.g. <code>&quot;stream&quot;</code>)</td></tr><tr><td><code>pool</code></td><td>pool code string</td><td>The Redis pool code</td></tr><tr><td><code>source</code></td><td>source string</td><td>Metrics source tag</td></tr></tbody></table><h3 id="fluxaorm-redis-queries-errors-counter" tabindex="-1"><a class="header-anchor" href="#fluxaorm-redis-queries-errors-counter"><span><code>fluxaorm_redis_queries_errors</code> (Counter)</span></a></h3><p>Counts the total number of Redis query errors.</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line"># HELP Total number of Redis queries errors</span>
<span class="line"># TYPE fluxaorm_redis_queries_errors counter</span>
<span class="line">fluxaorm_redis_queries_errors{pool=&quot;default&quot;,source=&quot;default&quot;} 123</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Labels:</strong></p><table><thead><tr><th>Label</th><th>Values</th><th>Description</th></tr></thead><tbody><tr><td><code>pool</code></td><td>pool code string</td><td>The Redis pool code</td></tr><tr><td><code>source</code></td><td>source string</td><td>Metrics source tag</td></tr></tbody></table><h2 id="changing-the-metrics-source" tabindex="-1"><a class="header-anchor" href="#changing-the-metrics-source"><span>Changing the Metrics Source</span></a></h2><p>Every metric includes a <code>source</code> label. By default it is set to <code>&quot;default&quot;</code>. You can change it by setting the <code>MetricsMetaKey</code> metadata on the context:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">ctx<span class="token punctuation">.</span><span class="token function">SetMetaData</span><span class="token punctuation">(</span>fluxaorm<span class="token punctuation">.</span>MetricsMetaKey<span class="token punctuation">,</span> <span class="token string">&quot;my_source&quot;</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>After setting this, all subsequent queries executed through <code>ctx</code> will be tagged with <code>source=&quot;my_source&quot;</code>:</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">fluxaorm_db_queries_seconds{le=&quot;0.005&quot;,operation=&quot;exec&quot;,pool=&quot;default&quot;,source=&quot;my_source&quot;} 100</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="summary-of-all-metrics" tabindex="-1"><a class="header-anchor" href="#summary-of-all-metrics"><span>Summary of All Metrics</span></a></h2><table><thead><tr><th>Metric Name</th><th>Type</th><th>Labels</th><th>Description</th></tr></thead><tbody><tr><td><code>fluxaorm_db_queries_seconds</code></td><td>Histogram</td><td><code>operation</code>, <code>pool</code>, <code>source</code></td><td>Duration of DB queries</td></tr><tr><td><code>fluxaorm_db_queries_errors</code></td><td>Counter</td><td><code>pool</code>, <code>source</code></td><td>Count of DB query errors</td></tr><tr><td><code>fluxaorm_redis_queries_seconds</code></td><td>Histogram</td><td><code>operation</code>, <code>pool</code>, <code>set</code>, <code>miss</code>, <code>pipeline</code>, <code>source</code></td><td>Duration of Redis queries</td></tr><tr><td><code>fluxaorm_redis_queries_block</code></td><td>Counter</td><td><code>operation</code>, <code>pool</code>, <code>source</code></td><td>Count of blocking Redis queries</td></tr><tr><td><code>fluxaorm_redis_queries_errors</code></td><td>Counter</td><td><code>pool</code>, <code>source</code></td><td>Count of Redis query errors</td></tr></tbody></table>`,43)]))}const c=s(n,[["render",d]]),l=JSON.parse('{"path":"/guide/metrics.html","title":"Metrics","lang":"en-US","frontmatter":{},"git":{"updatedTime":1772273114000,"contributors":[{"name":"lukaszlato","username":"lukaszlato","email":"latolukasz@gmail.com","commits":1,"url":"https://github.com/lukaszlato"},{"name":"Lukasz Lato","username":"","email":"latolukasz@gmail.com","commits":1}],"changelog":[{"hash":"456e3bba4fa5c1476f9974b418e090017f6b0cc2","time":1772273114000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"New ORM"},{"hash":"a514399d23186f1061ed658d00d613e7eb222857","time":1764600428000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"Context Cache"}]},"filePathRelative":"guide/metrics.md"}');export{c as comp,l as data};
